+        if (msg.id && this.pending.has(msg.id)) {
+          const { resolve } = this.pending.get(msg.id);
+          this.pending.delete(msg.id);
+          resolve(msg.result || msg.error || {});
+        }
+      } catch { /* skip non-JSON */ }
+    }
+  }
